# 输入获取
m, n, r = map(int, input().split())
a = list(map(int, input().split()))
b = list(map(int, input().split()))


def binarySearch(arr, target):
    low = 0
    high = len(arr) - 1

    while low <= high:
        mid = (low + high) >> 1
        midVal = arr[mid]

        if midVal > target:
            high = mid - 1
        elif midVal < target:
            low = mid + 1
        else:
            return mid

    return -low - 1


# 算法入口
def getResult():
    for ai in a:
        j = binarySearch(b, ai)
        if j >= 0:
            print(f"{ai} {b[j]}")
        else:
            insertIdx = -j - 1
            if insertIdx == len(b):
                continue
            if b[insertIdx] - ai <= r:
                print(f"{ai} {b[insertIdx]}")


# 算法调用
getResult()
